import { makeSimpleQuestion } from './base'
import type { Question, Topic } from './types'
import { HIGH_STANDARD_SUB_TOPICS, HIGH_STANDARD_MENTOR_HINTS, HIGH_STANDARD_CORRECT_SHORTENED } from './highStandardPolish'
import { polish as runPolish } from './polishPipeline'


const SOURCE = 'Floe secondary agent-generated syllabus bank'

function q(
  id: number,
  topic: Topic,
  chapter: string,
  title: string,
  prompt: string,
  correct: string,
  wrong: Array<[string, string]>,
  lesson: string,
): Question {
  return makeSimpleQuestion(
    id,
    topic,
    chapter,
    title,
    prompt,
    correct,
    wrong.map(([label, why]) => [label, why, lesson] as [string, string, string]),
    lesson,
    SOURCE,
  )
}

