export function topUpHighAgentGeneratedTrack(trackId: string, existing: Question[], minimum = 50) {
  if (existing.length >= minimum) return existing
  const generated = highAgentGeneratedQuestionsByTrack[trackId] || []
  const existingIds = new Set(existing.map((question) => question.id))
  const existingPrompts = new Set(existing.map(promptKey))
  const additions: Question[] = []

  for (const question of generated) {
    const key = promptKey(question)
    if (existingIds.has(question.id) || existingPrompts.has(key)) continue
    existingIds.add(question.id)
    existingPrompts.add(key)
    additions.push(question)
    if (existing.length + additions.length >= minimum) break
  }

  return [...existing, ...additions]
}

function promptKey(question: Question) {
  return question.prompt
    .toLowerCase()
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
}

export const highAgentGeneratedQuestionsByTrack: Record<string, Question[]> = Object.fromEntries(
  Object.entries(highAgentGeneratedBaseQuestionsByTrack).map(([trackId, questions]) => [
    trackId,
    runPolish(questions, [{ subTopics: HIGH_STANDARD_SUB_TOPICS, mentorHints: HIGH_STANDARD_MENTOR_HINTS, correctShortened: HIGH_STANDARD_CORRECT_SHORTENED, source: 'highStandard' }]),
  ]),
)
